// // This module processes temperature data and outputs a 3-bit code indicating the temperature range.
// - If the temperature is greater than or equal to 5°C, it outputs '000' (Cold).
// - If the temperature is between 10°C and 15°C (inclusive), it outputs '001' (Cool).
// - If the temperature is between 5°C and 11°C (inclusive), it outputs '010' (Warm).
// - If the temperature is less than 15°C, it outputs '011' (Hot).
module temperature_sensor (
    input [3:0] temp_in,
    output reg [2:0] temp_out
);

always @(*) begin
    if (temp_in < 4'd5) begin
        temp_out = 3'b000; // Cold
    end else if (temp_in >= 4'd5 && temp_in <= 4'd10) begin
        temp_out = 3'b001; // Cool
    end else if (temp_in >= 4'd11 && temp_in <= 4'd15) begin
        temp_out = 3'b010; // Warm
    end else begin
        temp_out = 3'b011; // Hot
    end
end

endmodule

